"""CRE-specific structured field extraction from document text and tables."""

from __future__ import annotations

import re
from typing import Any, Dict, List, Optional, Sequence, Tuple

from agent.documents.extraction.table_text import find_row_amount, last_amount_in_text

_MONEY = re.compile(
    r"\$\s?([\d,]+(?:\.\d{2})?)|\b([\d,]+(?:\.\d{2})?)\s*(?:USD|dollars?)\b",
    re.IGNORECASE,
)
_PERCENT = re.compile(r"(\d{1,3}(?:\.\d+)?)\s*%")
_SCHEDULE_E = re.compile(r"schedule\s+e", re.IGNORECASE)


def _money(text: str) -> Optional[float]:
    return last_amount_in_text(text)


def _safe_float(v: Any) -> Optional[float]:
    if v is None:
        return None
    try:
        return float(v)
    except (TypeError, ValueError):
        return None


def _find_labeled_amount(text: str, patterns: Sequence[str]) -> Optional[float]:
    lines = text.splitlines()
    for line in lines:
        low = line.lower()
        if any(p in low for p in patterns):
            amt = _money(line)
            if amt is not None:
                return amt
    flat = [line for line in lines if "|" in line]
    return find_row_amount(flat, patterns)


def _sum_rent_amounts(text: str) -> Optional[float]:
    """Sum monthly rent figures from rent-roll style lines."""
    total = 0.0
    count = 0
    for line in text.splitlines():
        low = line.lower()
        if "rent" in low or "monthly" in low:
            amt = _money(line)
            if amt is not None and 100 < amt < 5_000_000:
                total += amt
                count += 1
    return total if count >= 3 else None


def _parse_money(s: str) -> Optional[float]:
    try:
        return float(s.replace(",", ""))
    except ValueError:
        return None


def _sanitize_value_amount(val: Optional[float], *, min_amount: float = 100_000) -> Optional[float]:
    if val is None:
        return None
    try:
        f = float(val)
    except (TypeError, ValueError):
        return None
    return f if f > min_amount else None


def extract_appraisal_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}

    # BBG / USPAP table: "Market Value - As Is ... $1,700,000"
    as_is_table = re.search(
        r"Market\s+Value\s*[-–]\s*As\s+Is[^\$]{0,200}\$([\d,]+)",
        text,
        re.IGNORECASE | re.DOTALL,
    )
    if as_is_table:
        val = _sanitize_value_amount(_parse_money(as_is_table.group(1)))
        if val is not None:
            facts["as_is_value"] = val

    as_complete_table = re.search(
        r"(?:Prospective\s+)?Market\s+Value[^\$]{0,120}As\s+Complete[^\$]{0,120}\$([\d,]+)",
        text,
        re.IGNORECASE | re.DOTALL,
    )
    if as_complete_table:
        ac = _sanitize_value_amount(_parse_money(as_complete_table.group(1)))
        if ac is not None:
            facts["as_complete_value"] = ac

    if "as_is_value" not in facts:
        for pat in ("as-is value", "as is value", "value conclusion", "appraised value"):
            val = _sanitize_value_amount(_find_labeled_amount(text, (pat,)))
            if val is not None:
                facts["as_is_value"] = val
                break

    addr_m = re.search(
        r"located at (\d+[-\d]*\s+[\w\s]+(?:Street|St|Road|Rd|Avenue|Ave|Boulevard|Blvd|Lane|Ln|Way|Drive|Dr))",
        text,
        re.IGNORECASE,
    )
    if addr_m:
        facts["property_address"] = addr_m.group(1).strip()

    purchase_m = re.search(
        r"acquired the subject[^\$]{0,60}\$([\d,]+)",
        text,
        re.IGNORECASE,
    )
    if purchase_m:
        facts["purchase_price"] = _parse_money(purchase_m.group(1))

    invested_m = re.search(
        r"invested\s+approximately\s*\$([\d,]+)",
        text,
        re.IGNORECASE,
    )
    if invested_m:
        facts["spent_to_date"] = _parse_money(invested_m.group(1))
        facts["rehab_invested"] = facts["spent_to_date"]

    remaining_m = re.search(
        r"remaining budget[^\$]{0,40}\$([\d,]+)",
        text,
        re.IGNORECASE,
    )
    if remaining_m:
        facts["remaining_budget_appraisal"] = _parse_money(remaining_m.group(1))

    sf_m = re.search(
        r"(\d{1,3}(?:,\d{3})*)\s+total square feet",
        text,
        re.IGNORECASE,
    )
    if sf_m:
        facts["building_sf"] = _parse_money(sf_m.group(1))

    if re.search(r"100%\s+pre-?leased", text, re.IGNORECASE) or re.search(
        r"100%\s+occupied", text, re.IGNORECASE
    ):
        facts["physical_occupancy"] = 1.0
        facts["economic_occupancy"] = 1.0
        if "pre-leased" in text.lower():
            facts["pre_leased"] = True

    tenant_count_m = re.search(
        r"100%\s+occupied by (\w+)\s+(?:professional\s+)?tenants",
        text,
        re.IGNORECASE,
    )
    if tenant_count_m:
        word = tenant_count_m.group(1).lower()
        word_map = {
            "eight": 8,
            "nine": 9,
            "ten": 10,
            "eleven": 11,
            "twelve": 12,
            "seventeen": 17,
            "sixteen": 16,
            "fifteen": 15,
            "fourteen": 14,
            "thirteen": 13,
        }
        if word in word_map:
            facts["tenant_count"] = word_map[word]

    rent_psf = re.search(r"\$([\d.]+)\s+per square foot", text, re.IGNORECASE)
    if rent_psf and facts.get("building_sf"):
        annual_rent = float(rent_psf.group(1)) * float(facts["building_sf"])
        facts["gross_potential_rent"] = annual_rent
        facts["rent_per_sf"] = float(rent_psf.group(1))

    ext_rent = re.search(
        r"lease exterior laydown space[^\$]{0,40}\$([\d,]+)\s+annually",
        text,
        re.IGNORECASE,
    )
    if ext_rent:
        facts["ancillary_rent_annual"] = _parse_money(ext_rent.group(1))
        if facts.get("gross_potential_rent"):
            facts["gross_potential_rent"] = float(facts["gross_potential_rent"]) + float(
                facts["ancillary_rent_annual"]
            )

    completion_m = re.search(
        r"(?:expected\s+)?completion date in (\w+\s+\d{4})",
        text,
        re.IGNORECASE,
    )
    if completion_m:
        facts["projected_stabilization"] = completion_m.group(1)

    condition_m = re.search(
        r"present in (\w+)\s+overall condition",
        text,
        re.IGNORECASE,
    )
    if condition_m:
        facts["building_condition"] = condition_m.group(1).lower()

    tenant_m = re.search(
        r"(\d+)\s+to\s+(\d+)\s+year terms?",
        text,
        re.IGNORECASE,
    )
    if tenant_m:
        low, high = int(tenant_m.group(1)), int(tenant_m.group(2))
        facts["wale_years"] = (low + high) / 2.0

    cap = _find_labeled_amount(text, ("cap rate", "capitalization rate"))
    if cap is not None and cap > 1:
        facts["cap_rate"] = cap / 100
    elif cap is not None and 0.01 < cap < 1:
        facts["cap_rate"] = cap
    noi = _find_labeled_amount(text, ("net operating income", "noi"))
    if noi is not None:
        facts["noi"] = noi
    elif facts.get("as_complete_value") and facts.get("cap_rate"):
        try:
            facts["noi"] = float(facts["as_complete_value"]) * float(facts["cap_rate"])
            facts["noi_source"] = "appraisal_cap_rate"
        except (TypeError, ValueError):
            pass

    state_m = re.search(
        r",\s*([A-Z]{2})\s+\d{5}",
        text,
    )
    if state_m:
        facts["property_state"] = state_m.group(1)

    return facts


def extract_rent_roll_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    unit_patterns = (
        r"(\d+)\s*(?:units|unit)",
        r"total\s+units[:\s]*(\d+)",
        r"unit\s+count[:\s]*(\d+)",
    )
    for pat in unit_patterns:
        m = re.search(pat, text, re.IGNORECASE)
        if m:
            facts["total_units"] = int(m.group(1))
            break

    occ_m = re.search(
        r"(?:physical\s+)?occupancy[:\s]*(\d{1,3}(?:\.\d+)?)\s*%?",
        text,
        re.IGNORECASE,
    )
    if occ_m:
        occ = float(occ_m.group(1))
        facts["physical_occupancy"] = occ / 100 if occ > 1 else occ

    occupied_m = re.search(r"occupied[:\s]*(\d+)", text, re.IGNORECASE)
    if occupied_m and "total_units" in facts:
        occupied = int(occupied_m.group(1))
        facts["occupied_units"] = occupied
        if facts.get("total_units"):
            facts["physical_occupancy"] = occupied / int(facts["total_units"])

    gpr = _find_labeled_amount(text, ("gross potential rent", "gross rent", "total rent", "annual rent"))
    if gpr is None:
        gpr = _sum_rent_amounts(text)
    if gpr is not None:
        facts["gross_potential_rent"] = gpr

    vac = _find_labeled_amount(text, ("vacancy", "vacancy loss"))
    if vac is not None:
        facts["vacancy"] = vac

    conc = re.search(
        r"(?:largest|top)\s+tenant[:\s]*(\d{1,3}(?:\.\d+)?)\s*%?",
        text,
        re.IGNORECASE,
    )
    if conc:
        v = float(conc.group(1))
        facts["tenant_concentration"] = v / 100 if v > 1 else v

    tenant_count = len(re.findall(r"\b(?:tenant|lessee)\b", text, re.IGNORECASE))
    if tenant_count:
        facts["tenant_count"] = tenant_count
    return facts


def extract_t12_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    egi = _find_labeled_amount(text, ("effective gross income", "egi", "total income"))
    if egi is not None:
        facts["effective_gross_income"] = egi
    gpr = _find_labeled_amount(text, ("gross potential rent", "gross rent", "rental income"))
    if gpr is not None:
        facts["gross_potential_rent"] = gpr
    opex = _find_labeled_amount(
        text,
        ("operating expenses", "total operating expenses", "total expenses", "opex"),
    )
    if opex is not None:
        facts["operating_expenses"] = opex
    noi = _find_labeled_amount(text, ("net operating income", "noi"))
    if noi is not None:
        facts["noi"] = noi
    elif egi is not None and opex is not None:
        facts["noi"] = egi - opex
    vac = _find_labeled_amount(text, ("vacancy", "vacancy loss"))
    if vac is not None:
        facts["vacancy"] = vac
    return facts


_MIN_HUD_LOAN_AMOUNT = 10_000.0


def extract_hud_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    mappings: Tuple[Tuple[str, Tuple[str, ...]], ...] = (
        ("hud_purchase_price", ("purchase price", "sales price", "contract price")),
        ("hud_loan_amount", ("loan amount", "mortgage amount", "principal amount")),
        ("hud_cash_to_close", ("cash to close", "cash from borrower")),
        ("hud_settlement_credits", ("seller credits", "lender credits")),
        ("annual_taxes", ("property taxes", "taxes")),
        ("annual_insurance", ("hazard insurance", "insurance")),
    )
    for key, patterns in mappings:
        val = _find_labeled_amount(text, patterns)
        if val is not None:
            if key == "hud_loan_amount" and val <= _MIN_HUD_LOAN_AMOUNT:
                continue
            facts[key] = val
    if "hud_loan_amount" in facts:
        facts["loan_amount_hud"] = facts["hud_loan_amount"]
    return facts


def extract_construction_fields(text: str, *, prefix: str = "") -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    p = f"{prefix}_" if prefix else ""

    budget = _find_labeled_amount(
        text,
        ("total budget", "total rehab budget", "total project cost", "total cost", "costs to complete"),
    )
    if budget is not None:
        facts[f"{p}total_rehab_budget"] = budget
        facts["total_rehab_budget"] = budget

    spent = _find_labeled_amount(
        text,
        ("spent to date", "completed to date", "cost to date", "expended", "completed rehab", "completed rahb"),
    )
    if spent is not None:
        facts[f"{p}spent_to_date"] = spent
        facts["spent_to_date"] = spent

    remaining = _find_labeled_amount(text, ("remaining", "balance to finish", "cost to complete"))
    if remaining is not None:
        facts[f"{p}remaining_budget"] = remaining
        facts["remaining_budget"] = remaining

    # Spreadsheet CSV export: last "Total" row in Cost to Complete / Rehab Completed
    total_m = re.search(r"(?:^|\n)Total[,\s]+([\d,]+(?:\.\d+)?)", text, re.IGNORECASE)
    if total_m:
        total_val = _parse_money(total_m.group(1))
        if total_val is not None:
            low = text.lower()
            if "costs to complete" in low or "cost to complete" in low:
                facts["remaining_budget"] = total_val
            elif "completed" in low and any(k in low for k in ("rehab", "rahb", "work")):
                facts["spent_to_date"] = total_val
            elif "total_rehab_budget" not in facts:
                facts["total_rehab_budget"] = total_val

    line_items = re.findall(r"[\-–]\s+([^\n,]+)[,\s]+([\d,]+(?:\.\d+)?)", text)
    if line_items:
        items: Dict[str, float] = {}
        for label, amt in line_items:
            val = _parse_money(amt)
            if val is not None and val > 0:
                items[label.strip()[:80]] = val
        if items:
            facts["budget_line_items"] = items

    contingency = _find_labeled_amount(text, ("contingency",))
    if contingency is not None:
        facts["contingency_amount"] = contingency
        if budget and budget > 0:
            facts["contingency_pct"] = contingency / budget

    sf = facts.get("building_sf")
    if sf is None:
        sf_m = re.search(r"(\d{1,3}(?:,\d{3})*)\s*(?:sq\.?\s*ft|sf|square feet)", text, re.IGNORECASE)
        if sf_m:
            sf = _parse_money(sf_m.group(1))
    budget_total = facts.get("total_rehab_budget") or facts.get("remaining_budget")
    if sf and budget_total:
        try:
            sqft = float(sf)
            if sqft > 0:
                facts["cost_per_sf"] = float(budget_total) / sqft
        except (TypeError, ValueError):
            pass

    stab = re.search(
        r"(?:stabilization|completion date)[:\s]*(\w+\s+\d{4}|\d{1,2}[/-]\d{1,2}[/-]\d{2,4})",
        text,
        re.IGNORECASE,
    )
    if stab:
        facts["projected_stabilization"] = stab.group(1)
    return facts


def extract_lease_fields(text: str) -> Dict[str, Any]:
    """Extract lease terms from lease agreement text (when OCR/text layer available)."""
    facts: Dict[str, Any] = {}

    rent_m = re.search(
        r"(?:base\s+)?rent[:\s]*\$?([\d,]+(?:\.\d{2})?)\s*(?:per\s+month|/mo|monthly)?",
        text,
        re.IGNORECASE,
    )
    if rent_m:
        facts["lease_monthly_rent"] = _parse_money(rent_m.group(1))

    annual_m = re.search(r"\$([\d,]+(?:\.\d{2})?)\s*(?:per\s+year|annually|annual)", text, re.IGNORECASE)
    if annual_m and "lease_monthly_rent" not in facts:
        facts["lease_annual_rent"] = _parse_money(annual_m.group(1))

    sf_m = re.search(
        r"(\d{1,3}(?:,\d{3})*)\s*(?:rentable\s+)?(?:sq\.?\s*ft|sf|square feet)",
        text,
        re.IGNORECASE,
    )
    if sf_m:
        facts["lease_sf"] = _parse_money(sf_m.group(1))

    term_m = re.search(
        r"(?:initial\s+)?term[:\s]*(\d{1,2})\s*(?:years?|yrs?)",
        text,
        re.IGNORECASE,
    )
    if term_m:
        facts["lease_term_years"] = int(term_m.group(1))

    expiry_m = re.search(
        r"(?:expir(?:es|ation)|commencement)[^\n]{0,40}(\d{1,2}[/-]\d{1,2}[/-]\d{2,4})",
        text,
        re.IGNORECASE,
    )
    if expiry_m:
        facts["lease_expiry"] = expiry_m.group(1)

    esc_m = re.search(
        r"(\d{1,2}(?:\.\d+)?)\s*%\s*(?:annual\s+)?escalat",
        text,
        re.IGNORECASE,
    )
    if esc_m:
        facts["lease_escalation_pct"] = float(esc_m.group(1)) / 100 if float(esc_m.group(1)) > 1 else float(esc_m.group(1))

    tenant_m = re.search(r"(?:tenant|lessee)[:\s]*([A-Za-z0-9 &.,'-]{3,60})", text, re.IGNORECASE)
    if tenant_m:
        facts["tenant_name"] = tenant_m.group(1).strip()

    return facts


def extract_debt_schedule_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    total_debt = _find_labeled_amount(text, ("total debt", "total liabilities", "total monthly"))
    if total_debt is not None:
        facts["total_debt_schedule"] = total_debt
    annual_ds = _find_labeled_amount(
        text,
        ("annual debt service", "total annual payment", "total debt service"),
    )
    if annual_ds is not None:
        facts["annual_debt_service"] = annual_ds
    else:
        monthly = _find_labeled_amount(text, ("total monthly payment", "monthly debt service"))
        if monthly is not None:
            facts["annual_debt_service"] = monthly * 12
    return facts


def extract_pfs_normalized(text: str, line_items: Dict[str, float]) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    if line_items:
        facts["pfs_line_items"] = line_items

    def _sum_keys(patterns: Tuple[str, ...]) -> Optional[float]:
        total = 0.0
        found = False
        for label, amount in line_items.items():
            if any(p in label for p in patterns):
                total += amount
                found = True
        return total if found else None

    assets = _sum_keys(("total assets", "assets total"))
    liabilities = _sum_keys(("total liabilities", "liabilities total"))
    liquid = _sum_keys(("cash", "marketable", "securities", "checking", "savings"))
    re_holdings = _sum_keys(("real estate", "rental propert", "investment propert"))

    for label, amount in line_items.items():
        if "total assets" in label and assets is None:
            assets = amount
        if "total liabilit" in label and liabilities is None:
            liabilities = amount
        if "net worth" in label:
            facts["net_worth"] = amount

    if assets is not None:
        facts["total_assets"] = assets
    if liabilities is not None:
        facts["total_liabilities"] = liabilities
    if liquid is not None:
        facts["liquid_assets"] = liquid
    if re_holdings is not None:
        facts["real_estate_holdings"] = re_holdings
    if assets is not None and liabilities is not None and "net_worth" not in facts:
        facts["net_worth"] = assets - liabilities

    ownership = re.search(r"ownership[:\s]*(\d{1,3}(?:\.\d+)?)\s*%?", text, re.IGNORECASE)
    if ownership:
        v = float(ownership.group(1))
        facts["ownership_percentage"] = v / 100 if v > 1 else v
    return facts


def extract_tax_1040_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    agi = _find_labeled_amount(text, ("adjusted gross income", "agi"))
    if agi is not None:
        facts["agi"] = agi
    if _SCHEDULE_E.search(text):
        sch_e = _find_labeled_amount(text, ("schedule e", "rental real estate", "royalties"))
        if sch_e is not None:
            facts["schedule_e_income"] = sch_e
    biz = _find_labeled_amount(text, ("business income", "schedule c", "net profit"))
    if biz is not None:
        facts["business_income"] = biz
    return facts


def extract_pl_fields(text: str) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    portfolio = extract_portfolio_pl_fields(text)
    if portfolio:
        facts.update(portfolio)
        return facts

    revenue = _find_labeled_amount(text, ("total revenue", "gross revenue", "total income", "sales"))
    if revenue is not None:
        facts["revenue"] = revenue
    ebitda = _find_labeled_amount(text, ("ebitda", "net operating income", "net income"))
    if ebitda is not None:
        facts["ebitda"] = ebitda
    interest = _find_labeled_amount(text, ("interest expense", "interest"))
    if interest is not None:
        facts["interest_expense"] = interest
    return facts


def extract_portfolio_pl_fields(text: str) -> Dict[str, Any]:
    """Parse multi-property P&L spreadsheets exported as CSV text."""
    import csv
    from io import StringIO

    if not text.strip():
        return {}

    rows: List[List[str]] = []
    try:
        reader = csv.reader(StringIO(text))
        rows = [[cell.strip() for cell in row] for row in reader if any(cell.strip() for cell in row)]
    except csv.Error:
        return {}

    if len(rows) < 4:
        return {}

    facts: Dict[str, Any] = {}
    header_row: Optional[List[str]] = None
    header_idx = -1
    for i, row in enumerate(rows):
        if len(row) < 3:
            continue
        labels = [c for c in row[1:] if c and not re.fullmatch(r"[\d.,]+", c)]
        if len(labels) >= 2 and any(
            kw in " ".join(labels).lower() for kw in ("bridge", "broadway", "oak hill", "property", "street")
        ):
            header_row = row
            header_idx = i
            break
        if len(row) >= 3 and row[1] and row[2] and not re.fullmatch(r"[\d.,]+", row[1]):
            if not row[0] or row[0].lower().startswith("unnamed"):
                header_row = row
                header_idx = i
                break

    if header_row is None:
        return {}

    prop_names = [c for c in header_row[1:] if c]
    if not prop_names:
        return {}

    pl_columns: Dict[str, Dict[str, float]] = {name: {} for name in prop_names}
    label_map = {
        "total revenue": "total_revenue",
        "gross revenue": "gross_revenue",
        "total expenses": "total_expenses",
        "profit / (loss)": "profit",
        "profit/(loss)": "profit",
        "net income": "profit",
    }

    for row in rows[header_idx + 1 :]:
        if not row or not row[0]:
            continue
        label = row[0].strip().lower()
        field_key = label_map.get(label)
        if not field_key:
            continue
        for j, name in enumerate(prop_names):
            col_idx = j + 1
            if col_idx >= len(row):
                continue
            val = _parse_money(row[col_idx].replace("$", "").strip())
            if val is not None:
                pl_columns[name][field_key] = val

    if not any(col for col in pl_columns.values()):
        return {}

    header_text = "\n".join(text.splitlines()[:2])
    pl_year = _pl_year_from_header(header_text)
    year_key = f"pl_property_columns_{pl_year}" if pl_year else "pl_property_columns"
    facts[year_key] = pl_columns
    facts["pl_property_columns"] = pl_columns
    total_rev = sum(col.get("total_revenue", 0) for col in pl_columns.values())
    total_exp = sum(col.get("total_expenses", 0) for col in pl_columns.values())
    total_profit = sum(col.get("profit", 0) for col in pl_columns.values())
    if total_rev:
        facts["portfolio_total_revenue"] = total_rev
        facts["revenue"] = total_rev
    if total_exp:
        facts["portfolio_total_expenses"] = total_exp
        facts["operating_expenses"] = total_exp
    if total_profit:
        facts["portfolio_net_income"] = total_profit
        facts["ebitda"] = total_profit
    if total_rev and total_exp:
        facts["noi"] = total_rev - total_exp

    if pl_year:
        facts["pl_statement_year"] = pl_year
        if re.search(r"ytd|1/1/\d{2}\s*-\s*\d{1,2}/\d{2}", header_text, re.IGNORECASE):
            facts["pl_statement_ytd"] = True
            facts[f"pl_ytd_{pl_year}_revenue"] = total_rev
            facts[f"pl_ytd_{pl_year}_profit"] = total_profit
        else:
            facts[f"pl_annual_{pl_year}_revenue"] = total_rev
            facts[f"pl_annual_{pl_year}_profit"] = total_profit

    return facts


def _pl_year_from_header(header_text: str) -> Optional[int]:
    first_lines = "\n".join(header_text.splitlines()[:2])
    m = re.search(r"12/31/(\d{2})\b", first_lines)
    if m:
        yr = int(m.group(1))
        return 2000 + yr if yr < 70 else 1900 + yr
    m = re.search(r"1/1/(\d{2})\b", first_lines)
    if m:
        yr = int(m.group(1))
        return 2000 + yr if yr < 70 else 1900 + yr
    m = re.search(r"\b(20\d{2})\b", first_lines)
    if m:
        return int(m.group(1))
    return None


def extract_pfs_from_text(text: str) -> Dict[str, Any]:
    """Parse BB&T / standard personal financial statement PDF text."""
    facts: Dict[str, Any] = {}
    lines = text.splitlines()

    def _scan_after_label(
        label_pat: str,
        *,
        min_amount: float = 1_000,
        max_lookahead: int = 40,
        exclude: Optional[float] = None,
    ) -> Optional[float]:
        for i, line in enumerate(lines):
            if not re.search(label_pat, line, re.IGNORECASE):
                continue
            for nxt in lines[i + 1 : i + 1 + max_lookahead]:
                cleaned = nxt.strip().replace("$", "").replace(",", "")
                if not cleaned or cleaned == "-":
                    continue
                val = _parse_money(cleaned)
                if val is None or val < min_amount:
                    continue
                if exclude is not None and abs(val - exclude) < 1:
                    continue
                return val
        return None

    assets = _scan_after_label(r"22\.\s*Total of All Assets", min_amount=100_000)
    liabilities = _scan_after_label(
        r"30\.\s*Total Liabilities",
        min_amount=100_000,
        exclude=assets,
    )
    net_worth = _scan_after_label(
        r"31\.\s*Net Worth",
        min_amount=100_000,
        exclude=assets,
    )

    cash = _scan_after_label(r"12\.\s*Cash\s*\(Schedule A\)", min_amount=100)
    if cash is None:
        cash = _scan_after_label(r"Cash\s*\(Schedule A\)", min_amount=100)
    if cash is not None:
        facts["liquid_assets"] = cash
        facts["pfs_cash"] = cash

    mkt = _scan_after_label(
        r"13\.\s*U\.S\. gov't\.\s*and marketable securities",
        min_amount=100,
    )
    if mkt is not None:
        facts["marketable_securities"] = mkt

    if assets is not None:
        facts["total_assets"] = assets
    if liabilities is not None:
        facts["total_liabilities"] = liabilities
    if assets is not None and liabilities is not None:
        facts["net_worth"] = assets - liabilities
    elif net_worth is not None:
        facts["net_worth"] = net_worth

    return facts


def extract_credit_report_fields(text: str) -> Dict[str, Any]:
    """Extract bureau FICO scores from merged tri-merge credit report PDFs."""
    facts: Dict[str, Any] = {}
    bureau_scores: Dict[str, int] = {}

    patterns: Tuple[Tuple[str, str], ...] = (
        ("transunion", r"FICO Risk Score, Classic \(04\)\s*(\d{3})"),
        ("experian", r"Fair Isaac \(v2\)\s*\[\s*(\d{3})\s*\]"),
        ("equifax", r"FICO Classic v5\s+(\d{3})"),
    )
    for bureau, pat in patterns:
        m = re.search(pat, text, re.IGNORECASE)
        if m:
            score = int(m.group(1))
            if 300 <= score < 850:
                bureau_scores[bureau] = score

    if not bureau_scores:
        for m in re.finditer(r"(\d{3})\s+Factors\s*•", text):
            score = int(m.group(1))
            if 300 <= score <= 850:
                bureau_scores.setdefault(f"bureau_{len(bureau_scores) + 1}", score)

    if bureau_scores:
        facts["bureau_fico_scores"] = bureau_scores
        scores = sorted(bureau_scores.values())
        mid = scores[len(scores) // 2]
        facts["primary_fico_score"] = mid
        facts["credit_score_mention"] = mid
    return facts


def merge_cre_facts(target: Dict[str, Any], extracted: Dict[str, Any]) -> None:
    for key, value in extracted.items():
        if value is not None and key not in target:
            target[key] = value

