"""Serialize Azure DI tables into row-oriented text and structured field hints."""

from __future__ import annotations

import re
from typing import Any, Dict, List, Optional, Sequence, Tuple

_MONEY = re.compile(r"\$?\s*([\d,]+(?:\.\d{2})?)")


def build_table_grid(
    row_count: int,
    column_count: int,
    cells: Sequence[Any],
) -> List[List[str]]:
    """Build a sparse grid from Azure DI table cells."""
    grid: List[List[str]] = [
        ["" for _ in range(column_count)] for _ in range(row_count)
    ]
    for cell in cells:
        row_idx = int(getattr(cell, "row_index", 0) or 0)
        col_idx = int(getattr(cell, "column_index", 0) or 0)
        content = str(getattr(cell, "content", "") or "").strip()
        if 0 <= row_idx < row_count and 0 <= col_idx < column_count and content:
            if grid[row_idx][col_idx]:
                grid[row_idx][col_idx] = f"{grid[row_idx][col_idx]} {content}"
            else:
                grid[row_idx][col_idx] = content
    return grid


def grid_to_row_lines(grid: List[List[str]]) -> List[str]:
    """Join each table row into a single pipe-delimited line."""
    lines: List[str] = []
    for row in grid:
        cleaned = [c.strip() for c in row if c and c.strip()]
        if cleaned:
            lines.append(" | ".join(cleaned))
    return lines


def serialize_tables_from_result(tables: Sequence[Any]) -> Tuple[str, List[List[str]]]:
    """
    Return (text block for full_text, all row lines across tables).
    """
    if not tables:
        return "", []

    blocks: List[str] = []
    all_rows: List[List[str]] = []

    for table_idx, table in enumerate(tables, start=1):
        row_count = int(getattr(table, "row_count", 0) or 0)
        column_count = int(getattr(table, "column_count", 0) or 0)
        cells = getattr(table, "cells", None) or []
        if row_count <= 0 or column_count <= 0 or not cells:
            continue

        grid = build_table_grid(row_count, column_count, cells)
        row_lines = grid_to_row_lines(grid)
        if not row_lines:
            continue

        page_hint = ""
        regions = getattr(table, "bounding_regions", None) or []
        if regions:
            page_num = getattr(regions[0], "page_number", None)
            if page_num:
                page_hint = f" page {page_num}"

        blocks.append(f"[Table {table_idx}{page_hint}]")
        blocks.extend(row_lines)
        blocks.append("")
        all_rows.append(row_lines)

    return "\n".join(blocks).strip(), all_rows


def last_amount_in_text(text: str) -> Optional[float]:
    """Return the last plausible monetary amount in a string (IRS forms: amount in last column)."""
    if not text:
        return None
    candidates: List[float] = []
    for match in _MONEY.finditer(text):
        raw = match.group(1)
        if not raw:
            continue
        try:
            value = float(raw.replace(",", ""))
        except ValueError:
            continue
        if value >= 0:
            candidates.append(value)
    return candidates[-1] if candidates else None


def find_row_amount(rows: Sequence[str], label_patterns: Sequence[str]) -> Optional[float]:
    """Find amount in a table row whose text matches any label pattern."""
    for row in rows:
        row_lower = row.lower()
        for pattern in label_patterns:
            if pattern in row_lower:
                # Avoid "gross income" matching "gross profit" queries — handled by caller patterns
                amount = last_amount_in_text(row)
                if amount is not None:
                    return amount
    return None


def extract_tax_schedule_fields(all_row_lines: Sequence[Sequence[str]]) -> Dict[str, Any]:
    """Extract common Schedule C / tax line items from table rows."""
    flat_rows: List[str] = []
    for table_rows in all_row_lines:
        flat_rows.extend(table_rows)

    facts: Dict[str, Any] = {}
    mappings: Tuple[Tuple[str, Tuple[str, ...]], ...] = (
        ("schedule_c_gross_profit", ("gross profit",)),
        ("schedule_c_gross_income", ("gross income",)),
        ("schedule_c_net_profit", ("net profit", "net profit or (loss)", "net profit or loss")),
        ("schedule_c_total_expenses", ("total expenses",)),
        ("schedule_c_cost_of_goods_sold", ("cost of goods sold",)),
    )
    for field_key, patterns in mappings:
        amount = find_row_amount(flat_rows, patterns)
        if amount is not None:
            facts[field_key] = amount

    if "schedule_c_gross_profit" in facts:
        facts["gross_profit"] = facts["schedule_c_gross_profit"]
    if "schedule_c_gross_income" in facts:
        facts["gross_income"] = facts["schedule_c_gross_income"]

    # Fallback: search full text style rows in flat list for line 5 gross profit
    if "schedule_c_gross_profit" not in facts:
        for row in flat_rows:
            if re.search(r"\b5\b", row) and "gross profit" in row.lower():
                amount = last_amount_in_text(row)
                if amount is not None:
                    facts["schedule_c_gross_profit"] = amount
                    break

    return facts


def extract_pfs_fields_from_rows(all_row_lines: Sequence[Sequence[str]]) -> Dict[str, float]:
    """Extract label → amount from PFS-style table rows."""
    line_items: Dict[str, float] = {}
    for table_rows in all_row_lines:
        for row in table_rows:
            parts = [p.strip() for p in row.split("|")]
            if len(parts) < 2:
                continue
            label = parts[0].lower()
            if len(label) < 3:
                continue
            amount = last_amount_in_text(" | ".join(parts[1:]))
            if amount is None:
                continue
            if label not in line_items:
                line_items[label] = amount
    return line_items


def extract_bank_statement_fields(all_row_lines: Sequence[Sequence[str]]) -> Dict[str, Any]:
    facts: Dict[str, Any] = {}
    flat_rows: List[str] = []
    for table_rows in all_row_lines:
        flat_rows.extend(table_rows)

    for row in flat_rows:
        row_lower = row.lower()
        amount = last_amount_in_text(row)
        if amount is None:
            continue
        if "ending balance" in row_lower or "closing balance" in row_lower:
            facts["closing_balance"] = amount
        elif "beginning balance" in row_lower or "opening balance" in row_lower:
            facts["opening_balance"] = amount

    amounts = [last_amount_in_text(r) for r in flat_rows]
    amounts = [a for a in amounts if a is not None]
    if amounts and "amounts_found" not in facts:
        facts["amounts_found"] = amounts[:10]
    return facts

